import React from 'react';
import { Link } from 'react-router-dom';
import PublicLayout from '../components/layouts/publiclayout';

const HomePage: React.FC = () => {
    return (
        <PublicLayout>
            <main className="hero">
                <div className="container">
                    <div className="hero-content">
                        <div className="hero-text">
                            <h1>Welcome to Channel4Me</h1>
                            <p>AI-Powered Doctor Matching & Instant Booking</p>
                            <p>Find the perfect specialist, book appointments instantly, and manage your healthcare—all in one intelligent platform.</p>

                            <div className="hero-buttons">
                                <Link to="/doctor/register/step1" className="btn btn-primary">Register as Doctor</Link>
                                <Link to="/doctor/login" className="btn btn-outline">Doctor Login</Link>
                            </div>
                        </div>
                    </div>
                </div>
            </main>
        </PublicLayout>
    );
};

export default HomePage;
